import re

def extract_class_and_method_names(directory):
    class_and_method_pattern = re.compile(r'class\s+(\w+)\s*\(.*?\):|def\s+(\w+)\s*\((.*?)\):')
    class_and_method_names = []

    for root, dirs, files in os.walk(directory):
        for file in files:
            if file.endswith('.py'):
                with open(os.path.join(root, file), 'r', encoding='utf-8') as f:
                    content = f.read()
                    matches = class_and_method_pattern.findall(content)
                    for match in matches:
                        if match[0]:
                            class_and_method_names.append(f'Class: {match[0]}')
                        if match[1]:
                            class_and_method_names.append(f'Method: {match[1]}')

    return class_and_method_names

